css:
.print-format { page-width: 240mm; page-height: 105mm; orientation: Landscape; margin-top: 4mm; margin-bottom: 4mm; margin-left: 5mm; margin-right: 0mm; padding: 0 !important; }
body { font-family: Arial, Helvetica, sans-serif; margin: 0; padding: 0; color: #111; }
.ts { position: relative; width: 100%; box-sizing: border-box; padding-right: 35mm; padding-bottom: 4mm; }
.ts-row { display: flex; justify-content: space-between; align-items: flex-start; gap: 4mm; }
.ts-main { flex: 1; min-width: 0; }
.ts-name { font-size: 22pt; font-weight: 700; line-height: 1.05; margin: 0 0 1.5mm 0; }
.ts-wohnung { font-size: 12pt; color: #222; margin-bottom: 0.4mm; }
.ts-wohnung-lage { font-size: 10pt; color: #555; margin-bottom: 0; }
.ts-zeitraum { font-size: 11pt; margin-top: 2mm; color: #111; }
.ts-tag { background: transparent !important; color: #777 !important; font-size: 9pt; font-weight: 600; text-transform: uppercase; letter-spacing: 0.2pt; padding: 0; margin-right: 1.5mm; border: 0; display: inline-block; }
.ts-kontakt-grid { margin-top: 2mm; font-size: 10.5pt; color: #222; line-height: 1.45; }
.ts-kontakt-grid .ts-tag { width: 12mm; }
.ts-qr { width: 26mm; flex-shrink: 0; text-align: center; }
.ts-qr img { width: 26mm; height: 26mm; display: block; }
.ts-vormieter { margin-top: 2.5mm; padding-top: 1.5mm; border-top: 0.3pt solid #ddd; font-size: 9pt; font-style: italic; color: #666; }
.ts-vormieter .ts-tag { font-style: normal; color: #888; }
.ts-tab { position: absolute; top: 0; right: 5mm; width: 28mm; height: 88mm; border-left: 0.4pt solid #bbb; display: flex; align-items: center; justify-content: center; overflow: hidden; }
.ts-tab-name { writing-mode: vertical-rl; transform: rotate(180deg); font-size: 24pt; font-weight: 700; line-height: 1; white-space: nowrap; letter-spacing: 0.5pt; }

html:
{%- set ctx = doc.get_trennstreifen_context() -%}
<div class="ts">
  <div class="ts-row">
    <div class="ts-main">
      <div class="ts-name">{{ ctx.hauptmieter or doc.name }}</div>
      <div class="ts-wohnung">
        {{ ctx.wohnung_adresse }}{% if ctx.wohnung_gebaeudeteil %} · {{ ctx.wohnung_gebaeudeteil }}{% endif %}
      </div>
      {%- if ctx.wohnung_lage %}
      <div class="ts-wohnung-lage">{{ ctx.wohnung_lage }}</div>
      {%- endif %}
      <div class="ts-zeitraum">
        <span class="ts-tag">{{ _("Mietzeitraum") }}</span>
        {{ frappe.utils.formatdate(ctx.von) if ctx.von else "—" }}
        –
        {{ frappe.utils.formatdate(ctx.bis) if ctx.bis else _("unbefristet") }}
      </div>
      <div class="ts-kontakt-grid">
        {%- if ctx.telefon %}<div><span class="ts-tag">{{ _("Tel.") }}</span>{{ ctx.telefon }}</div>{% endif %}
        {%- if ctx.mobil %}<div><span class="ts-tag">{{ _("Mobil") }}</span>{{ ctx.mobil }}</div>{% endif %}
        {%- if ctx.email %}<div><span class="ts-tag">{{ _("Email") }}</span>{{ ctx.email }}</div>{% endif %}
      </div>
    </div>
    {%- if ctx.qr_data_url %}
    <div class="ts-qr">
      <img src="{{ ctx.qr_data_url }}" alt="QR"/>
    </div>
    {%- endif %}
  </div>
  {%- if ctx.vormieter %}
  <div class="ts-vormieter"><span class="ts-tag">{{ _("vorher") }}:</span>{{ ctx.vormieter }}</div>
  {%- endif %}
  <div class="ts-tab"><div class="ts-tab-name">{{ ctx.hauptmieter or doc.name }}</div></div>
</div>
